function validate(value) {
  return new Promise((resolve, reject) => {
    if (!value) reject(new Error('empty'));
    else resolve(value);
  });
}

def reject_items(items):
    return [x for x in items if x != 'bad']
result = reject_items(['good', 'bad', 'good'])

List<String> items = Arrays.asList("good", "bad", "good");
